import { useMemo, useState } from 'react';
import Link from 'next/link';
import Head from 'next/head';
import { getAllPosts, PostMeta } from '../lib/posts';
import Search from '../components/Search';
import Pagination from '../components/Pagination';
import TagList from '../components/TagList';

const POSTS_PER_PAGE = 5;

export default function Home({ posts }: { posts: PostMeta[] }) {
  const [query, setQuery] = useState('');
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [page, setPage] = useState(1);

  const filtered = useMemo(() => {
    let list = posts;
    if (query) {
      const q = query.toLowerCase();
      list = list.filter((p) => p.title.toLowerCase().includes(q) || (p.tags || []).some((t) => t.toLowerCase().includes(q)));
    }
    if (selectedTag) {
      list = list.filter((p) => (p.tags || []).includes(selectedTag));
    }
    return list;
  }, [posts, query, selectedTag]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / POSTS_PER_PAGE));
  const start = (page - 1) * POSTS_PER_PAGE;
  const pagePosts = filtered.slice(start, start + POSTS_PER_PAGE);

  const allTags = Array.from(new Set(posts.flatMap((p) => p.tags || []))).sort();

  return (
    <>
      <Head>
        <title>My Blog</title>
        <meta name="description" content="A personal blog built with Next.js and TypeScript" />
      </Head>
      <div className="mb-6">
        <h1 className="text-3xl font-bold">My Blog</h1>
        <p className="text-gray-600 dark:text-gray-300 mt-2">Thoughts, tutorials, and experiments.</p>
      </div>

      <div className="mb-6 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <Search value={query} onChange={setQuery} placeholder="Search by title or tag" />
        <TagList tags={allTags} active={selectedTag} onSelect={setSelectedTag} />
      </div>

      <div className="space-y-6">
        {pagePosts.map((post) => (
          <article key={post.slug} className="p-4 border rounded border-gray-100 dark:border-zinc-700">
            <h2 className="text-xl font-semibold">
              <Link href={`/posts/${post.slug}`}>{post.title}</Link>
            </h2>
            <div className="text-sm text-gray-500 dark:text-gray-400">{post.date} • {post.author}</div>
            <p className="text-gray-700 dark:text-gray-300 mt-2">{post.excerpt}</p>
            <div className="mt-3 text-sm">
              {(post.tags || []).map((t) => (
                <button key={t} onClick={() => setSelectedTag(t)} className="mr-2 text-xs px-2 py-1 bg-gray-100 dark:bg-zinc-800 rounded">
                  #{t}
                </button>
              ))}
            </div>
          </article>
        ))}
      </div>

      <div className="mt-8">
        <Pagination current={page} total={totalPages} onChange={(p: number) => setPage(p)} />
      </div>
    </>
  );
}

export function getStaticProps() {
  const posts = getAllPosts();
  return { props: { posts } };
}
